class InMemoryWalletDataSource : WalletDataSource {
    private val balances = mutableMapOf<String, WalletBalance>()

    override suspend fun getBalance(userId: String): WalletBalance {
        return balances[userId] ?: WalletBalance(
            userId = userId,
            available = BigDecimal.ZERO,
            currency = "USD"
