    }

    override suspend fun debit(userId: String, amount: BigDecimal, currency: String): Boolean {
        val current = getBalance(userId)
        if (current.currency != currency || current.available < amount) return false
        balances[userId] = current.copy(available = current.available.subtract(amount))
        return true
    }

    override suspend fun credit(userId: String, amount: BigDecimal, currency: String): Boolean {
        val current = balances[userId] ?: WalletBalance(userId, BigDecimal.ZERO, currency)
        if (current.currency != currency) return false
        balances[userId] = current.copy(available = current.available.add(amount))
        return true
    }

    suspend fun seed(userId: String, amount: BigDecimal, currency: String) {
        balances[userId] = WalletBalance(userId, amount, currency)
    }
}